frappe.ui.form.on("Customer", {
	refresh(frm) {
		if (frm.is_new()) return;
		frappe.db.get_list("Party Link", {
			or_filters: [
				["primary_party", "=", frm.doc.name],
				["secondary_party", "=", frm.doc.name],
			],
			limit: 1,
		}).then((rows) => {
			if (rows && rows.length) return;
			frm.add_custom_button(__("Create Supplier counterpart"), () => {
				frappe.confirm(
					__("Create a linked Supplier for {0}?", [frm.doc.name.bold()]),
					() => {
						frappe.call({
							method: "agriops_suite.party.make_counterparty",
							args: { role: "Customer", name: frm.doc.name },
							freeze: true,
							freeze_message: __("Creating counterpart..."),
						}).then((r) => {
							const m = r.message || {};
							frappe.msgprint({
								title: __("Party linked"),
								indicator: "green",
								message: __("Linked to Supplier {0}{1}", [
									(m.counterpart || "").bold(),
									m.created ? __(" (newly created)") : __(" (existing record)"),
								]),
							});
							frm.reload_doc();
						});
					}
				);
			}, __("VAC"));
		});
	},
});

