frappe.ui.form.on('Item', {
    refresh: function(frm){ pd_set_template(frm); pd_fetch_molecule(frm); },
    item_group: function(frm){ pd_set_template(frm); },
    pd_pesticide_technical_name: function(frm){ pd_fetch_molecule(frm); }
});
function pd_set_template(frm){
    if(!frm.doc.item_group){ return; }
    frappe.db.get_value('Item Group', frm.doc.item_group, 'product_detail_template').then(function(r){
        var t = (r.message || {}).product_detail_template || '';
        if(frm.doc.product_detail_template !== t){
            frm.doc.product_detail_template = t;
            frm.refresh_field('product_detail_template');
            frm.refresh_fields();
        }
    });
}
function pd_fetch_molecule(frm){
    var tn = frm.doc.pd_pesticide_technical_name;
    if(!tn){ frm.doc.pd_tn_pests=''; frm.doc.pd_tn_crops='';
             frm.refresh_field('pd_tn_pests'); frm.refresh_field('pd_tn_crops'); return; }
    frappe.db.get_doc('Technical Name', tn).then(function(doc){
        frm.doc.pd_tn_pests = (doc.pests_covered || []).map(function(r){return r.pest;}).join(', ');
        frm.doc.pd_tn_crops = (doc.crops_covered || []).map(function(r){return r.crop;}).join(', ');
        frm.refresh_field('pd_tn_pests'); frm.refresh_field('pd_tn_crops');
    });
}

// LedgerLift — Form client script (consolidated).
frappe.ui.form.on('LedgerLift Tracker', {
    refresh(frm) {
        const is_admin = frappe.session.user === 'Administrator' || frappe.user.has_role('System Manager');
        if (frm.doc.recovery_status === 'Paid' && !frm.is_new() && !is_admin) {
            frm.disable_form();
            frm.set_intro(__('This record is marked Paid and is locked. Contact an administrator to make changes.'), 'orange');
        }
        if (!frm.is_new() && frm.doc.recovery_status !== 'Paid') {
            frm.add_custom_button(__('Log Follow-up'), () => log_follow_up(frm)).addClass('btn-primary');
        }
        if (frm.doc.customer && frm.doc.recovery_status !== 'Paid') {
            frm.add_custom_button(__('Fetch Current Balance'), () => fetch_current_balance(frm));
        }
        if (frm.doc.credit_limit && frm.doc.outstanding_amount > frm.doc.credit_limit) {
            frm.dashboard.set_headline(__('Outstanding exceeds credit limit by {0}',
                [format_currency(frm.doc.outstanding_amount - frm.doc.credit_limit)]));
        }
    },
    oldest_invoice_date(frm) { set_days_outstanding(frm); },
    customer(frm) {
        if (frm.doc.customer && !frm.doc.outstanding_amount) { fetch_current_balance(frm, true); }
    },
});

function set_days_outstanding(frm) {
    frm.set_value('days_outstanding', frm.doc.oldest_invoice_date
        ? frappe.datetime.get_day_diff(frappe.datetime.get_today(), frm.doc.oldest_invoice_date) : 0);
}

function fetch_current_balance(frm, silent) {
    if (!frm.doc.customer) { if (!silent) frappe.msgprint(__('Select a customer first.')); return; }
    frappe.call({
        method: 'credit_recovery_fetch_balance',
        args: { customer: frm.doc.customer },
        freeze: !silent, freeze_message: __('Fetching current balance…'),
        callback(r) {
            const d = r.message || {};
            frm.set_value('outstanding_amount', d.outstanding_amount || 0);
            if (d.oldest_invoice_date) frm.set_value('oldest_invoice_date', d.oldest_invoice_date);
            frappe.show_alert({ message: __('Fetched {0} (net customer balance)',
                [format_currency(d.outstanding_amount || 0)]), indicator: 'green' });
        },
    });
}

function log_follow_up(frm) {
    const d = new frappe.ui.Dialog({
        title: __('Log follow-up — {0}', [frm.doc.customer]),
        fields: [
            {fieldtype:'Date', fieldname:'follow_up_date', label:__('Interaction date'), default: frappe.datetime.get_today(), reqd:1},
            {fieldtype:'Column Break'},
            {fieldtype:'Select', fieldname:'outcome', label:__('Outcome'), reqd:1,
             options:['Called - No Answer','Spoke - Promised','Spoke - Slipped','Partial Payment','Left Message','Visited','Refused','Dispute','Other'].join('\n')},
            {fieldtype:'Section Break', label:__('Promise')},
            {fieldtype:'Currency', fieldname:'promised_amount', label:__('Promised amount')},
            {fieldtype:'Date', fieldname:'promised_date', label:__('Promised date')},
            {fieldtype:'Column Break'},
            {fieldtype:'Date', fieldname:'next_follow_up_date', label:__('Next follow-up date')},
            {fieldtype:'Section Break'},
            {fieldtype:'Small Text', fieldname:'notes', label:__('Notes')},
        ],
        primary_action_label: __('Save follow-up'),
        primary_action(v) {
            frm.add_child('follow_ups', {
                follow_up_date: v.follow_up_date, outcome: v.outcome,
                promised_amount: v.promised_amount, promised_date: v.promised_date,
                next_follow_up_date: v.next_follow_up_date, notes: v.notes,
                logged_by: frappe.session.user,
            });
            frm.set_value('last_contact_date', v.follow_up_date);
            if (v.next_follow_up_date) frm.set_value('next_follow_up_date', v.next_follow_up_date);
            if (v.promised_amount) frm.set_value('promised_amount', v.promised_amount);
            if (v.promised_date) frm.set_value('promised_payment_date', v.promised_date);
            const map = {
                'Spoke - Promised':'Payment Promised', 'Spoke - Slipped':'Payment Promised',
                'Partial Payment':'Partial Payment', 'Refused':'Escalated', 'Dispute':'Dispute',
                'Called - No Answer':'Contacted', 'Left Message':'Contacted', 'Visited':'Contacted',
            };
            if (map[v.outcome]) frm.set_value('recovery_status', map[v.outcome]);
            d.hide();
            frm.save().then(() => frappe.show_alert({message: __('Follow-up logged'), indicator:'green'}));
        },
    });
    d.show();
}

// LedgerLift — List view client script.
// Installed as a Client Script record (dt: LedgerLift, view: List).
// Provides the status indicator colors and the four quick filters as a
// "Quick Filters" button group. Buttons compute dates at click time, so
// "Due Today" / "Overdue" are always relative to the actual current date
// (saved static filters cannot do this).

frappe.listview_settings['LedgerLift Tracker'] = {
    add_fields: ['recovery_status', 'priority', 'next_follow_up_date', 'outstanding_amount'],

    get_indicator(doc) {
        const colors = {
            'Paid': 'green',
            'Payment Promised': 'yellow',
            'Contacted': 'orange',
            'Escalated': 'red',
            'Current': 'blue',
            'Reminder Due': 'purple',
            'Partial Payment': 'cyan',
            'Dispute': 'grey',
        };
        return [
            __(doc.recovery_status),
            colors[doc.recovery_status] || 'grey',
            'recovery_status,=,' + doc.recovery_status,
        ];
    },

    onload(listview) {
        const apply_filters = async (filters) => {
            await listview.filter_area.clear();
            await listview.filter_area.add(filters);
        };
        const group = __('Quick Filters');

        listview.page.add_inner_button(__('Due Today'), () => apply_filters([
            ['LedgerLift Tracker', 'next_follow_up_date', '=', frappe.datetime.get_today()],
            ['LedgerLift Tracker', 'recovery_status', '!=', 'Paid'],
        ]), group);

        listview.page.add_inner_button(__('Overdue Follow-ups'), () => apply_filters([
            ['LedgerLift Tracker', 'next_follow_up_date', '<', frappe.datetime.get_today()],
            ['LedgerLift Tracker', 'recovery_status', '!=', 'Paid'],
        ]), group);

        listview.page.add_inner_button(__('Critical Accounts'), () => apply_filters([
            ['LedgerLift Tracker', 'priority', '=', 'Critical'],
            ['LedgerLift Tracker', 'recovery_status', '!=', 'Paid'],
        ]), group);

        listview.page.add_inner_button(__('Promised Payments'), () => apply_filters([
            ['LedgerLift Tracker', 'recovery_status', '=', 'Payment Promised'],
        ]), group);
    },
};
